// appendChild nümunəsi
const newParagraph = document.createElement('p');
newParagraph.textContent = 'Bu yeni paraqrafdır';

const container = document.querySelector('.container');
container.appendChild(newParagraph); // Yeni paraqraf konteynerə əlavə olunur

// removeChild nümunəsi
const container = document.querySelector('.container');
const paragraph = document.querySelector('.paragraph');
if (paragraph) {
  container.removeChild(paragraph); // Paraqraf konteynerdən silinir
}

// replaceChild nümunəsi
const newParagraph = document.createElement('p');
newParagraph.textContent = 'Yeni paraqraf';

const container = document.querySelector('.container');
const oldParagraph = document.querySelector('.paragraph');
if (oldParagraph) {
  container.replaceChild(newParagraph, oldParagraph); // Köhnə paraqraf yeni ilə əvəz olunur
}

// Səhvə yol açan nümunə
const container = document.querySelector('.container');
const nonExistent = document.querySelector('.non-existent');
container.removeChild(nonExistent); // TypeError: Failed to execute 'removeChild' on 'Node': parameter is not a Node

// Düzgün yol
const paragraph = document.querySelector('.paragraph');
if (paragraph && container.contains(paragraph)) {
  container.removeChild(paragraph);
} else {
  console.log('Element tapılmadı və ya konteynerin övladı deyil');
}

// appendChild example
const newParagraph = document.createElement('p');
newParagraph.textContent = 'This is a new paragraph';

const container = document.querySelector('.container');
container.appendChild(newParagraph); // Adds the new paragraph to the container

// removeChild example
const container = document.querySelector('.container');
const paragraph = document.querySelector('.paragraph');
if (paragraph) {
  container.removeChild(paragraph); // Removes the paragraph from the container
}

// replaceChild example
const newParagraph = document.createElement('p');
newParagraph.textContent = 'New paragraph';

const container = document.querySelector('.container');
const oldParagraph = document.querySelector('.paragraph');
if (oldParagraph) {
  container.replaceChild(newParagraph, oldParagraph); // Replaces the old paragraph with the new one
}

// Error-prone example
const container = document.querySelector('.container');
const nonExistent = document.querySelector('.non-existent');
container.removeChild(nonExistent); // TypeError: Failed to execute 'removeChild' on 'Node': parameter is not a Node

// Correct approach
const paragraph = document.querySelector('.paragraph');
if (paragraph && container.contains(paragraph)) {
  container.removeChild(paragraph);
} else {
  console.log('Element not found or not a child of the container');
}

// Пример appendChild
const newParagraph = document.createElement('p');
newParagraph.textContent = 'Это новый параграф';

const container = document.querySelector('.container');
container.appendChild(newParagraph); // Добавляет новый параграф в контейнер

// Пример removeChild
const container = document.querySelector('.container');
const paragraph = document.querySelector('.paragraph');
if (paragraph) {
  container.removeChild(paragraph); // Удаляет параграф из контейнера
}

// Пример replaceChild
const newParagraph = document.createElement('p');
newParagraph.textContent = 'Новый параграф';

const container = document.querySelector('.container');
const oldParagraph = document.querySelector('.paragraph');
if (oldParagraph) {
  container.replaceChild(newParagraph, oldParagraph); // Заменяет старый параграф новым
}

// Пример с ошибкой
const container = document.querySelector('.container');
const nonExistent = document.querySelector('.non-existent');
container.removeChild(nonExistent); // TypeError: Failed to execute 'removeChild' on 'Node': parameter is not a Node

// Правильный подход
const paragraph = document.querySelector('.paragraph');
if (paragraph && container.contains(paragraph)) {
  container.removeChild(paragraph);
} else {
  console.log('Элемент не найден или не является дочерним для контейнера');
}
